import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { worker as workerApi } from '../services/api';

const CITIES = ['Mumbai', 'Delhi', 'Bengaluru', 'Chennai', 'Hyderabad', 'Pune', 'Kolkata', 'Ahmedabad'];

export default function Onboarding() {
  const { user, setUser } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({
    name: user?.name || '',
    platform: 'swiggy',
    city: 'Mumbai',
    weeklyEarnings: 5000,
    upiId: '',
    aadhaarLast4: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const update = (key, val) => setForm(f => ({ ...f, [key]: val }));

  const handleSubmit = async () => {
    setLoading(true); setError('');
    try {
      const res = await workerApi.updateProfile({
        ...form,
        operatingZone: { city: form.city },
        weeklyEarnings: Number(form.weeklyEarnings),
      });
      setUser(res.data);
      navigate('/policy');
    } catch (err) {
      setError(err.response?.data?.error || 'Update failed');
    } finally { setLoading(false); }
  };

  return (
    <div className="page">
      <div style={{ marginBottom: 24 }}>
        <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
          {[1, 2, 3].map(s => (
            <div key={s} style={{
              flex: 1, height: 4, borderRadius: 4,
              background: s <= step ? '#6c63ff' : '#e0e0e0',
              transition: 'background 0.3s'
            }} />
          ))}
        </div>
        <p style={{ color: '#888', fontSize: 13 }}>Step {step} of 3</p>
      </div>

      {step === 1 && (
        <div className="card">
          <h2 className="section-title">Tell us about yourself</h2>
          <div className="input-group">
            <label>Full Name</label>
            <input className="input" placeholder="Rajan Kumar" value={form.name} onChange={e => update('name', e.target.value)} />
          </div>
          <div className="input-group">
            <label>Platform you work on</label>
            <div style={{ display: 'flex', gap: 10 }}>
              {['swiggy', 'zomato', 'both'].map(p => (
                <button key={p} onClick={() => update('platform', p)}
                  style={{
                    flex: 1, padding: '10px', borderRadius: 10, border: '1.5px solid',
                    borderColor: form.platform === p ? '#6c63ff' : '#e0e0e0',
                    background: form.platform === p ? '#f0effe' : '#fff',
                    color: form.platform === p ? '#6c63ff' : '#555',
                    fontWeight: 600, cursor: 'pointer', fontSize: 13, textTransform: 'capitalize'
                  }}>{p}</button>
              ))}
            </div>
          </div>
          <div className="input-group">
            <label>Aadhaar last 4 digits (for KYC)</label>
            <input className="input" type="tel" maxLength={4} placeholder="XXXX" value={form.aadhaarLast4} onChange={e => update('aadhaarLast4', e.target.value.replace(/\D/g, ''))} />
          </div>
          <button className="btn btn-primary" onClick={() => setStep(2)} disabled={!form.name || form.aadhaarLast4.length !== 4}>Next →</button>
        </div>
      )}

      {step === 2 && (
        <div className="card">
          <h2 className="section-title">Your work zone & earnings</h2>
          <div className="input-group">
            <label>City you deliver in</label>
            <select className="input" value={form.city} onChange={e => update('city', e.target.value)}>
              {CITIES.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>
          <div className="input-group">
            <label>Estimated weekly earnings (₹)</label>
            <input className="input" type="number" placeholder="5000" value={form.weeklyEarnings} onChange={e => update('weeklyEarnings', e.target.value)} />
            <p style={{ fontSize: 12, color: '#888', marginTop: 4 }}>
              This helps us calculate your payout accurately. Approx ₹{Math.round(form.weeklyEarnings / 60)}/hr
            </p>
          </div>
          <div style={{ display: 'flex', gap: 10 }}>
            <button className="btn btn-secondary" onClick={() => setStep(1)}>← Back</button>
            <button className="btn btn-primary" onClick={() => setStep(3)}>Next →</button>
          </div>
        </div>
      )}

      {step === 3 && (
        <div className="card">
          <h2 className="section-title">Payout details</h2>
          <div className="alert alert-info">
            Claims are transferred directly to your UPI ID — no bank forms needed.
          </div>
          <div className="input-group">
            <label>UPI ID</label>
            <input className="input" placeholder="rajan@upi or 9876543210@paytm" value={form.upiId} onChange={e => update('upiId', e.target.value)} />
          </div>
          {error && <div className="alert alert-error">{error}</div>}
          <div style={{ display: 'flex', gap: 10 }}>
            <button className="btn btn-secondary" onClick={() => setStep(2)}>← Back</button>
            <button className="btn btn-primary" onClick={handleSubmit} disabled={loading || !form.upiId}>
              {loading ? 'Saving...' : 'Start Coverage 🛡️'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
